import subprocess
import sys
import os
import hashlib
import json
from pathlib import Path


def verify_requirements_file(requirements_path):
    """Verify requirements file integrity and content"""
    if not os.path.exists(requirements_path):
        print(f"Error: Requirements file not found: {requirements_path}")
        sys.exit(1)
    
    with open(requirements_path, 'r') as f:
        content = f.read()
    
    if not content.strip():
        print("Error: Requirements file is empty")
        sys.exit(1)
    
    suspicious_patterns = ['&&', '||', ';', '`', '$(', '${']
    for pattern in suspicious_patterns:
        if pattern in content:
            print(f"Warning: Suspicious pattern '{pattern}' found in requirements file")
            print("Manual review required before installation")
            sys.exit(1)
    
    return True


def create_requirements_lock(requirements_path):
    """Create a lock file with current package versions"""
    lock_path = requirements_path + '.lock'
    
    try:
        result = subprocess.run(
            [sys.executable, '-m', 'pip', 'freeze'],
            capture_output=True,
            text=True,
            check=True,
            timeout=30
        )
        
        with open(lock_path, 'w') as f:
            f.write(result.stdout)
        
        print(f"Created lock file: {lock_path}")
    except Exception as e:
        print(f"Warning: Could not create lock file: {e}")


def install_requirements(requirements_path, use_upgrade=False):
    """Install requirements with security checks"""
    
    verify_requirements_file(requirements_path)
    
    cmd = [
        sys.executable,
        '-m',
        'pip',
        'install',
        '-r',
        requirements_path
    ]
    
    if use_upgrade:
        print("WARNING: --upgrade flag requested but disabled for security")
        print("Upgrading packages without hash verification poses security risks:")
        print("  - Package substitution attacks")
        print("  - Compromised package repositories")
        print("  - Breaking changes in dependencies")
        print("\nRecommended approach:")
        print("  1. Use pinned versions in requirements.txt")
        print("  2. Use pip-compile to generate requirements with hashes")
        print("  3. Test upgrades in staging environment first")
        print("  4. Use --require-hashes flag for production")
    
    print(f"\nInstalling packages from: {requirements_path}")
    print("Command:", ' '.join(cmd))
    
    try:
        result = subprocess.run(
            cmd,
            check=True,
            timeout=600,
            env={**os.environ, 'PYTHONUNBUFFERED': '1'}
        )
        
        print("\n✓ Installation completed successfully")
        
        create_requirements_lock(requirements_path)
        
        return result.returncode
        
    except subprocess.TimeoutExpired:
        print("Error: Installation timed out after 10 minutes")
        sys.exit(1)
    except subprocess.CalledProcessError as e:
        print(f"Error: Installation failed with exit code {e.returncode}")
        sys.exit(1)
    except Exception as e:
        print(f"Error: Unexpected error during installation: {e}")
        sys.exit(1)


def main():
    requirements_file = os.environ.get('REQUIREMENTS_FILE', 'requirements.txt')
    use_upgrade = os.environ.get('PIP_UPGRADE', '').lower() == 'true'
    
    if use_upgrade:
        print("=" * 70)
        print("SECURITY WARNING: Upgrade mode disabled")
        print("=" * 70)
    
    print(f"Python version: {sys.version}")
    print(f"Pip version: ", end='')
    subprocess.run([sys.executable, '-m', 'pip', '--version'])
    
    install_requirements(requirements_file, use_upgrade)


if __name__ == '__main__':
    main()